mapper:
//Query que nos ayuda a buscar un usuario en la BD por nombre y retorna una //instancia del modelo Usuario
SELECT "idUsuario", "idRol", "idTipoUsuario", "idProgramaEducativo", "nombre", "apellidoPaterno", "username" AS usuario, "password" AS contrasena, "email" AS correo, "telefono", "claveUsuario", "estatus", "tiempoCreacion", "tempoActualizacion" AS tiempoActualizacion FROM usuario WHERE "username" = #{usuario} AND "estatus" = '1'
//Query que nos ayuda a buscar un usuario en la BD por correo y retorna una //instancia del modelo Usuario
SELECT * FROM usuario WHERE "email" = #{correo}
//Query que nos ayuda a registrar un usario en la BD
INSERT INTO usuario ( "nombre", "apellidoPaterno", "apellidoMaterno", "claveUsuario", "email", "telefono", "username", "password", "estatus", "idRol", "idTipoUsuario", "idProgramaEducativo", "tiempoCreacion" ) VALUES ( #{nombre}, #{apellidoPaterno}, #{apellidoMaterno}, #{claveUsuario}, #{correo}, #{telefono}, #{usuario}, #{contrasena}, '1', #{idRol}, #{idTipoUsuario}, #{idProgramaEducativo}, CURRENT_TIMESTAMP )
//Query que nos retorna un resultado de tipo Modelo Usuario al buscalo por un ID
SELECT "idUsuario", "idRol", "idTipoUsuario", "idProgramaEducativo", "nombre", "apellidoPaterno", "apellidoMaterno", "username" AS usuario, "email" AS correo, "telefono", "claveUsuario", "estatus", "tiempoCreacion", "tempoActualizacion" AS tiempoActualizacion FROM usuario WHERE "idUsuario" = #{idUsuario}
//Query que nos ayuda a editar la informacion de un usuario ya activo
UPDATE usuario SET "idRol" = #{idRol}, "idTipoUsuario" = #{idTipoUsuario}, "idProgramaEducativo" = #{idProgramaEducativo}, "nombre" = #{nombre}, "apellidoPaterno" = #{apellidoPaterno}, "apellidoMaterno" = #{apellidoMaterno}, "email" = #{correo}, "telefono" = #{telefono}, "tempoActualizacion" = CURRENT_TIMESTAMP WHERE "idUsuario" = #{idUsuario}
//Query que nos ayuda a cambiar el estatus de un usuario que ya se encuentra //dentro de la BD
UPDATE usuario SET "estatus" = CASE WHEN "estatus" = B'1' THEN B'0' ELSE B'1' END WHERE "idUsuario" = #{idUsuario}
